193→      body: [
194→        {
195→          type: 'heading',
196→          props: { text: 'Abastecimento' },
197→        },
198→        {
199→          type: 'balance',
200→          props: {
201→            points: '25.720',
202→            nested: { value: 'R$ 7.716,00' },
203→          },
204→        },
205→      ],
206→    });
207→  });
208→
209→  it('returns primitive values unchanged', () => {
210→    expect(interpolateDeep(42, CONTEXT)).toBe(42);
211→    expect(interpolateDeep(true, CONTEXT)).toBe(true);
